6: import { CancellationToken } from '../../../../base/common/cancellation.js';
7: import { ITextModel } from '../../../common/model.js';
8: import { computeIndentLevel } from '../../../common/model/utils.js';
9: import { FoldingMarkers } from '../../../common/languages/languageConfiguration.js';
10: import { ILanguageConfigurationService } from '../../../common/languages/languageConfigurationRegistry.js';
11: import { FoldingRegions, MAX_LINE_NUMBER } from './foldingRanges.js';
12: import { FoldingLimitReporter, RangeProvider } from './folding.js';
13: 
14: const MAX_FOLDING_REGIONS_FOR_INDENT_DEFAULT = 5000;
15: 
16: const ID_INDENT_PROVIDER = 'indent';
17: 
18: export class IndentRangeProvider implements RangeProvider {
19: 	readonly id = ID_INDENT_PROVIDER;
20: 
21: 	constructor(
22: 		private readonly editorModel: ITextModel,
23: 		private readonly languageConfigurationService: ILanguageConfigurationService,
24: 		private readonly foldingRangesLimit: FoldingLimitReporter
25: 	) { }
26: 
27: 	dispose() { }
28: 
29: 	compute(cancelationToken: CancellationToken,): Promise<FoldingRegions> {
30: 		const foldingRules = this.languageConfigurationService.getLanguageConfiguration(this.editorModel.getLanguageId()).foldingRules;
31: 		const offSide = foldingRules && !!foldingRules.offSide;
32: 		const markers = foldingRules && foldingRules.markers;
33: 		return Promise.resolve(computeRanges(this.editorModel, offSide, markers, this.foldingRangesLimit));
34: 	}
35: }
