03c\u003c bit);\n59: \t\t}\n60: \t}\n61: }\n62: \n63: export class FoldingRegions {\n64: \tprivate readonly _startIndexes: Uint32Array;\n65: \tprivate readonly _endIndexes: Uint32Array;\n66: \tprivate readonly _collapseStates: BitField;\n67: \tprivate readonly _userDefinedStates: BitField;\n68: \tprivate readonly _recoveredStates: BitField;\n69: \n70: \tprivate _parentsComputed: boolean;\n71: \tprivate readonly _types: Array\u003cstring | undefined\u003e | undefined;\n72: \n73: \tconstructor(startIndexes: Uint32Array, endIndexes: Uint32Array, types?: Array\u003cstring | undefined\u003e) {\n74: \t\tif (startIndexes.length !== endIndexes.length || startIndexes.length \u003e MAX_FOLDING_REGIONS) {\n75: \t\t\tthrow new Error('invalid startIndexes or endIndexes size');\n76: \t\t}\n77: \t\tthis._startIndexes = startIndexes;\n78: \t\tthis._endIndexes = endIndexes;\n79: \t\tthis._collapseStates = new BitField(startIndexes.length);\n80: \t\tthis._userDefinedStates = new BitField(startIndexes.length);\n81: \t\tthis._recoveredStates = new BitField(startIndexes.length);\n82: \t\tthis._types = types;\n83: \t\tthis._parentsComputed = false;\n84: \t}\n85: \n86: \tprivate ensureParentIndices() {\n87: \t\tif (!this._parentsComputed) {\n88: \t\t\tthis._parentsComputed = true;\n89: \t\t\tconst parentIndexes: number[] = [];\n90: \t\t\tconst isInsideLast = (startLineNumber: number, endLineNumber: number) =\u003e {\n91: \t\t\t\tconst index = parentIndexes[parentIndexes.length - 1];\n92: \t\t\t\treturn this.getStartLineNumber(index) \u003c= startLineNumber \u0026\u0026 this.getEndLineNumber(index) \u003e= endLineNumber;\n93: \t\t\t};\n94: \t\t\tfor (let i = 0, len = this._startIndexes.length; i \u003c len; i++) {\n95: \t\t\t\tconst startLineNumber = this._startIndexes[i];\n96: \t\t\t\tconst endLineNumber = this._endIndexes[i];\n97: \t\t\t\tif (startLineNumber \u003e MAX_LINE_NUMBER || endLineNumber \u003e MAX_LINE_NUMBER) {\n98: \t\t\t\t\tthrow new Error('startLineNumber or endLineNumber must not exceed ' + MAX_LINE_NUMBER);\n99: \t\t\t\t}\n100: \t\t\t\twhile (parentIndexes.length \u003e 0 \u0026\u0026 !isInsideLast(startLineNumber, endLineNumber)) {\n101: \t\t\t\t\tparentIndexes.pop();\n102: \t\t\t\t}\n103: \t\t\t\tconst parentIndex = parentIndexes.length \u003e 0 ? parentIndexes[parentIndexes.length - 1] : -1;\n104: \t\t\t\tparentIndexes.push(i);\n105: \t\t\t\tthis._startIndexes[i] = startLineNumber + ((parentIndex \u0026 0xFF) \u003c\u003c 24);\n106: \t\t\t\tthis._endIndexes[i] = endLineNumber + ((parentIndex \u0026 0xFF00) \u003c\u003c 16);\n107: \t\t\t}\n108: \t\t}\n109: \t}\n110: \n111: \tpublic get length(): number {\n112: \t\treturn this._startIndexes.length;\n113: \t}\n114: \n115: \tpublic getStartLineNumber(index: number): number {\n116: \t\treturn this._startIndexes[index] \u0026 MAX_LINE_NUMBER;\n117: \t}\n118: \n119: \tpublic getEndLineNumber(index: number): number {\n120: \t\treturn this._endIndexes[index] \u0026 MAX_LINE_NUMBER;\n121: \t}\n122: \n123: \tpublic getType(index: number): string | undefined {\n124: \t\treturn this._types ? this._types[index] : undefined;\n125: \t}\n126: \n127: \tpublic hasTypes() {\n128: \t\treturn !!this._types;\n129: \t}\n130: \n131: \tpublic isCollapsed(index: number): boolean {\n132: \t\treturn this._collapseStates.get(index);\n133: \t}\n134: \n135: \tpublic setCollapsed(index: number, newState: boolean) {\n136: \t\tthis._collapseStates.set(index, newState);\n137: \t}\n138: \n139: \tprivate isUserDefined(index: number): boolean {\n140: \t\treturn this._userDefinedStates.get(index);\n141: \t}\n142: \n143: \tprivate setUserDefined(index: number, newState: boolean) {\n144: \t\treturn this._userDefinedStates.set(index, newState);\n145: \t}\n146: \n147: \tprivate isRecovered(index: number): boolean {\n148: \t\treturn this._recoveredStates.get(index);\n149: \t}\n150: \n151: \tprivate setRecovered(index: number, newState: boolean) {\n152: \t\treturn this._recoveredStates.set(index, newState);\n153: \t}\n154: \n155: \tpublic getSource(index: number): FoldSource {\n156: \t\tif (this.isUserDefined(index)) {\n157: \t\t\treturn FoldSource.userDefined;\n158: \t\t} else if (this.isRecovered(index)) {\n159: \t\t\treturn FoldSource.recovered;\n160: \t\t}\n161: \t\treturn FoldSource.provider;\n162: \t}\n163: \n164: \tpublic setSource(index: number, source: FoldSource): void {\n165: \t\tif (source === FoldSource.userDefined) {\n166: \t\t\tthis.setUserDefined(index, true);\n167: \t\t\tthis.setRecovered(index, false);\n168: \t\t} else if (source === FoldSource.recovered) {\n169: \t\t\tthis.setUserDefined(index, false);\n170: \t\t\tthis.setRecovered(index, true);\n171: \t\t} else {\n172: \t\t\tthis.setUserDefined(index, false);\n173: \t\t\tthis.setRecovered(index, false);\n174: \t\t}\n175: \t}\n176: \n177: \tpublic setCollapsedAllOfType(type: string, newState: boolean) {\n178: \t\tlet hasChanged = false;\n179: \t\tif (this._types) {\n180: \t\t\tfor (let i = 0; i \u003c this._types.length; i++) {\n181: \t\t\t\tif (this._types[i] === type) {\n182: \t\t\t\t\tthis.setCollapsed(i, newState);\n183: \t\t\t\t\thasChanged = true;\n184: \t\t\t\t}\n185: \t\t\t}\n186: \t\t}\n187: \t\treturn hasChanged;\n188: \t}\n189: \n190: \tpublic toRegion(index: number): FoldingRegion {\n191: \t\treturn new FoldingRegion(this, index);\n192: \t}\n193: \n194: \tpublic getParentIndex(index: number) {\n195: \t\tthis.ensureParentIndices();\n196: \t\tconst parent = ((this._startIndexes[index] \u0026 MASK_INDENT) \u003e\u003e\u003e 24) + ((this._endIndexes[index] \u0026 MASK_INDENT) \u003e\u003e\u003e 16);\n197: \t\tif (parent === MAX_FOLDING_REGIONS) {\n198: \t\t\treturn -1;\n199: \t\t}\n200: \t\treturn parent;\n201: \t}\n202: \n203: \tpublic contains(index: number, line: number) {\n204: \t\treturn this.getStartLineNumber(index) \u003c= line \u0026\u0026 this.getEndLineNumber(index) \u003e= line;\n205: \t}\n206: \n207: \tprivate findIndex(line: number) {\n208: \t\tlet low = 0, high = this._startIndexes.length;\n209: \t\tif (high === 0) {\n210: \t\t\treturn -1; // no children\n211: \t\t}\n212: \t\twhile (low \u003c high) {\n213: \t\t\tconst mid = Math.floor((low + high) / 2);\n214: \t\t\tif (line \u003c this.getStartLineNumber(mid)) {\n215: \t\t\t\thigh = mid;\n216: \t\t\t} else {\n217: \t\t\t\tlow = mid + 1;\n218: \t\t\t}\n219: \t\t}\n220: \t\treturn low - 1;\n221: \t}\n222: \n223: \tpublic findRange(line: number): number {\n224: \t\tlet index = this.findIndex(line);\n225: \t\tif (index \u003e= 0) {\n226: \t\t\tconst endLineNumber = this.getEndLineNumber(index);\n227: \t\t\tif (endLineNumber \u003e= line) {\n228: \t\t\t\treturn index;\n229: \t\t\t}\n230: \t\t\tindex = this.getParentIndex(index);\n231: \t\t\twhile (index !== -1) {\n232: \t\t\t\tif (this.contains(index, line)) {\n233: \t\t\t\t\treturn index;\n234: \t\t\t\t}\n235: \t\t\t\tindex = this.getParentIndex(index);\n236: \t\t\t}\n237: \t\t}\n238: \t\treturn -1;\n239: \t}\n240: \n241: \n242: \tpublic toString() {\n243: \t\tconst res: string[] = [];\n244: \t\tfor (let i = 0; i \u003c this.length; i++) {\n245: \t\t\tres[i] = `[${foldSourceAbbr[this.getSource(i)]}${this.isCollapsed(i) ? '+' : '-'}] ${this.getStartLineNumber(i)}/${this.getEndLineNumber(i)}`;\n246: \t\t}\n247: \t\treturn res.join(', ');\n248: \t}\n249: \n250: \tpublic toFoldRange(index: number): FoldRange {\n251: \t\treturn {\n252: \t\t\tstartLineNumber: this._startIndexes[index] \u0026 MAX_LINE_NUMBER,\n253: \t\t\tendLineNumber: this._endIndexes[index] \u0026 MAX_LINE_NUMBER,\n254: \t\t\ttype: this._types ? this._types[index] : undefined,\n255: \t\t\tisCollapsed: this.isCollapsed(index),\n256: \t\t\tsource: this.getSource(index)\n257: \t\t};\n258: \t}\n259: \n260: \tpublic static fromFoldRanges(ranges: FoldRange[]): FoldingRegions {\n261: \t\tconst rangesLength = ranges.length;\n262: \t\tconst startIndexes = new Uint32Array(rangesLength);\n263: \t\tconst endIndexes = new Uint32Array(rangesLength);\n264: \t\tlet types: Array\u003cstring | undefined\u003e | undefined = [];\n265: \t\tlet gotTypes = false;\n266: \t\tfor (let i = 0; i \u003c rangesLength; i++) {\n267: \t\t\tconst range = ranges[i];\n268: \t\t\tstartIndexes[i] = range.startLineNumber;\n269: \t\t\tendIndexes[i] = range.endLineNumber;\n270: \t\t\ttypes.push(range.type);\n271: \t\t\tif (range.type) {\n272: \t\t\t\tgotTypes = true;\n273: \t\t\t}\n274: \t\t}\n275: \t\tif (!gotTypes) {\n276: \t\t\ttypes = undefined;\n277: \t\t}\n278: \t\tconst regions = new FoldingRegions(startIndexes, endIndexes, types);\n279: \t\tfor (let i = 0; i \u003c rangesLength; i++) {\n280: \t\t\tif (ranges[i].isCollapsed) {\n281: \t\t\t\tregions.setCollapsed(i, true);\n282: \t\t\t}\n283: \t\t\tregions.setSource(i, ranges[i].source);\n284: \t\t}\n285: \t\treturn regions;\n286: \t}\n287: \n288: \t/**\n289: \t * Two inputs, each a FoldingRegions or a FoldRange[], are merged.\n290: \t * Each input must be pre-sorted on startLineNumber.\n291: \t * The first list is assumed to always include all regions currently defined by range providers.\n292: \t * The second list only contains the previously collapsed and all manual ranges.\n293: \t * If the line position matches, the range of the new range is taken, and the range is no longer manual\n294: \t * When an entry in one list overlaps an entry in the other, the second list's entry \"wins\" and\n295: \t * overlapping entries in the first list are discarded.\n296: \t * Invalid entries are discarded. An entry is invalid if:\n297: \t * \t\tthe start and end line numbers aren't a valid range of line numbers,\n298: \t * \t\tit is out of sequence or has the same start line as a preceding entry,\n299: \t * \t\tit overlaps a preceding entry and is not fully contained by that entry.\n300: \t */\n301: \tpublic static sanitizeAndMerge(\n302: \t\trangesA: FoldingRegions | FoldRange[],\n303: \t\trangesB: FoldingRegions | FoldRange[],\n304: \t\tmaxLineNumber: number | undefined,\n305: \t\tselection?: SelectedLines\n306: \t): FoldRange[] {\n307: \n308: \t\tmax