.isCollapsed \u0026\u0026 nextB.source === FoldSource.provider) {\n346: \t\t\t\t\t\t// a previously collapsed range\n347: \t\t\t\t\t\tuseRange.source = FoldSource.recovered;\n348: \t\t\t\t\t}\n349: \t\t\t\t}\n350: \t\t\t\tnextB = getB(++indexB);\n351: \t\t\t} else {\n352: \t\t\t\t// nextA is next. The user folded B set takes precedence and we sometimes need to look\n353: \t\t\t\t// ahead in it to check for an upcoming conflict.\n354: \t\t\t\tlet scanIndex = indexB;\n355: \t\t\t\tlet prescanB = nextB;\n356: \t\t\t\twhile (true) {\n357: \t\t\t\t\tif (!prescanB || prescanB.startLineNumber \u003e nextA!.endLineNumber) {\n358: \t\t\t\t\t\tuseRange = nextA;\n359: \t\t\t\t\t\tbreak; // no conflict, use this nextA\n360: \t\t\t\t\t}\n361: \t\t\t\t\tif (prescanB.source === FoldSource.userDefined \u0026\u0026 prescanB.endLineNumber \u003e nextA!.endLineNumber) {\n362: \t\t\t\t\t\t// we found a user folded range, it wins\n363: \t\t\t\t\t\tbreak; // without setting nextResult, so this nextA gets skipped\n364: \t\t\t\t\t}\n365: \t\t\t\t\tprescanB = getB(++scanIndex);\n366: \t\t\t\t}\n367: \t\t\t\tnextA = getA(++indexA);\n368: \t\t\t}\n369: \n370: \t\t\tif (useRange) {\n371: \t\t\t\twhile (topStackedRange\n372: \t\t\t\t\t\u0026\u0026 topStackedRange.endLineNumber \u003c useRange.startLineNumber) {\n373: \t\t\t\t\ttopStackedRange = stackedRanges.pop();\n374: \t\t\t\t}\n375: \t\t\t\tif (useRange.endLineNumber \u003e useRange.startLineNumber\n376: \t\t\t\t\t\u0026\u0026 useRange.startLineNumber \u003e prevLineNumber\n377: \t\t\t\t\t\u0026\u0026 useRange.endLineNumber \u003c= maxLineNumber\n378: \t\t\t\t\t\u0026\u0026 (!topStackedRange\n379: \t\t\t\t\t\t|| topStackedRange.endLineNumber \u003e= useRange.endLineNumber)) {\n380: \t\t\t\t\tresultRanges.push(useRange);\n381: \t\t\t\t\tprevLineNumber = useRange.startLineNumber;\n382: \t\t\t\t\tif (topStackedRange) {\n383: \t\t\t\t\t\tstackedRanges.push(topStackedRange);\n384: \t\t\t\t\t}\n385: \t\t\t\t\ttopStackedRange = useRange;\n386: \t\t\t\t}\n387: \t\t\t}\n388: \n389: \t\t}\n390: \t\treturn resultRanges;\n391: \t}\n392: \n393: }\n394: \n395: export class FoldingRegion {\n396: \n397: \tconstructor(private readonly ranges: FoldingRegions, private index: number) {\n398: \t}\n399: \n400: \tpublic get startLineNumber() {\n401: \t\treturn this.ranges.getStartLineNumber(this.index);\n402: \t}\n403: \n404: \tpublic get endLineNumber() {\n405: \t\treturn this.ranges.getEndLineNumber(this.index);\n406: \t}\n407: \n408: \tpublic get regionIndex() {\n409: \t\treturn this.index;\n410: \t}\n411: \n412: \tpublic get parentIndex() {\n413: \t\treturn this.ranges.getParentIndex(this.index);\n414: \t}\n415: \n416: \tpublic get isCollapsed() {\n417: \t\treturn this.ranges.isCollapsed(this.index);\n418: \t}\n419: \n420: \tcontainedBy(range: ILineRange): boolean {\n421: \t\treturn range.startLineNumber \u003c= this.startLineNumber \u0026\u0026 range.endLineNumber \u003e= this.endLineNumber;\n422: \t}\n423: \tcontainsLine(lineNumber: number) {\n424: \t\treturn this.startLineNumber \u003c= lineNumber \u0026\u0026 lineNumber \u003c= this.endLineNumber;\n425: \t}\n426: \thidesLine(lineNumber: number) {\n427: \t\treturn this.startLineNumber \u003c lineNumber \u0026\u0026 lineNumber \u003c= this.endLineNumber;\n428: \t}\n429: }\n430: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/vscode--138f619c@7344a1807afca4c7dbac122b9a8952fd73001f85/-/blob/src/vs/editor/contrib/folding/browser/foldingRanges.ts"}", "annotations": null, "meta": null}], "structuredContent": {"content": "1: /*---------------------------------------------------------------------------------------------
