6: import assert from 'assert';
7: import { ensureNoDisposablesAreLeakedInTestSuite } from '../../../../../base/test/common/utils.js';
8: import { FoldingMarkers } from '../../../../common/languages/languageConfiguration.js';
9: import { computeRanges } from '../../browser/indentRangeProvider.js';
