import { CancellationToken } from '../../../../base/common/cancellation.js';
import { ITextModel } from '../../../common/model.js';
import { FoldingRegions } from './foldingRanges.js';
import { FoldingLimitReporter, RangeProvider } from './folding.js';

/**
 * Represents a named folding region detected from `#region <name>` / `#endregion` markers.
 */
export interface NamedRegion {
	/** The name extracted from the `#region <name>` marker. Empty string if no name was given. */
	name: string;
	/** 1-based start line (the line containing `#region`). */
	startLineNumber: number;
	/** 1-based end line (the line containing `#endregion`). */
	endLineNumber: number;
}

/**
 * Matches a `#region` marker, optionally preceded by a comment prefix, and captures
 * the optional region name that follows.
 *
 * Supported comment styles: `//`, `#`, `--`, `/*`, `<!--`, `rem` (batch), `'` (VB)
 * The pattern also matches a bare `#region` with no prefix so that it works for
 * languages where `#region` is a first-class directive (e.g. C#, PowerShell).
 *
 * Capture group 1: the trimmed region name (may be empty).
 */
const REGION_START_PATTERN = /^\s*(?:\/\/|#|--|\/\*|<!--|rem\b|')\s*#region\b\s*(.*?)\s*(?:\*\/)?\s*$|^\s*#region\b\s*(.*?)\s*$/i;

/**
 * Matches a `#endregion` marker with the same optional comment prefixes.
 */
const REGION_END_PATTERN = /^\s*(?:\/\/|#|--|\/\*|<!--|rem\b|')\s*#endregion\b|^\s*#endregion\b/i;

const ID_NAMED_REGION_PROVIDER = 'namedRegion';

/**
 * Scans `model` for `#region <name>` / `#endregion` pairs and returns the list of
 * matched named regions in document order (top to bottom).
 *
 * Unmatched start markers (no corresponding `#endregion`) are ignored.
 * Nested regions are supported.
 */
export function computeNamedRegions(model: ITextModel): NamedRegion[] {
	const lineCount = model.getLineCount();

	interface PendingRegion {
		name: string;
		startLineNumber: number;
	}

	const stack: PendingRegion[] = [];
	const result: NamedRegion[] = [];

	for (let lineNumber = 1; lineNumber <= lineCount; lineNumber++) {
		const lineContent = model.getLineContent(lineNumber);

		const startMatch = lineContent.match(REGION_START_PATTERN);
		if (startMatch) {
			// Capture group 1 (comment-prefixed form) or group 2 (bare form)
			const name = (startMatch[1] ?? startMatch[2] ?? '').trim();
			stack.push({ name, startLineNumber: lineNumber });
			continue;
		}

		if (REGION_END_PATTERN.test(lineContent)) {
			const pending = stack.pop();
			if (pending) {
				result.push({
					name: pending.name,
					startLineNumber: pending.startLineNumber,
					endLineNumber: lineNumber,
				});
			}
		}
	}

	// Sort by start line so consumers can rely on document order
	result.sort((a, b) => a.startLineNumber - b.startLineNumber);

	return result;
}

/**
 * A `RangeProvider` that exposes `#region` / `#endregion` blocks as folding ranges.
 * This provider works in addition to the language-specific providers and produces
 * regions whose `type` is set to `'namedRegion'` so that they can be distinguished
 * from other folding ranges.
 */
export class NamedFoldingRangeProvider implements RangeProvider {
	readonly id = ID_NAMED_REGION_PROVIDER;

	constructor(
		private readonly editorModel: ITextModel,
		private readonly foldingRangesLimit: FoldingLimitReporter,
	) { }

	dispose(): void { }

	compute(_cancellationToken: CancellationToken): Promise<FoldingRegions | null> {
		const namedRegions = computeNamedRegions(this.editorModel);

		const count = namedRegions.length;
		const limit = this.foldingRangesLimit.limit;
		const effectiveCount = Math.min(count, limit);
		this.foldingRangesLimit.update(count, count > limit ? limit : false);

		const startIndexes = new Uint32Array(effectiveCount);
		const endIndexes = new Uint32Array(effectiveCount);
		const types: Array<string | undefined> = new Array(effectiveCount);

		for (let i = 0; i < effectiveCount; i++) {
			startIndexes[i] = namedRegions[i].startLineNumber;
			endIndexes[i] = namedRegions[i].endLineNumber;
			types[i] = `namedRegion:${namedRegions[i].name}`;
		}

		return Promise.resolve(new FoldingRegions(startIndexes, endIndexes, types));
	}
}

