/**
 * Action: Go to Named Region
 *
 * Displays a quick-pick listing all `#region <name>` / `#endregion` blocks in the current
 * file. Selecting an entry navigates the cursor to that region's start line and ensures it
 * is unfolded.
 *
 * Keybinding: Ctrl+Shift+R (⌘+Shift+R on macOS)
 */
class GoToNamedRegionAction extends EditorAction {

	constructor() {
		super({
			id: 'editor.action.goToNamedRegion',
			label: nls.localize2('goToNamedRegion.label', "Go to Named Region…"),
			precondition: CONTEXT_FOLDING_ENABLED,
			kbOpts: {
				kbExpr: EditorContextKeys.editorTextFocus,
				primary: KeyMod.CtrlCmd | KeyMod.Shift | KeyCode.KeyR,
				weight: KeybindingWeight.EditorContrib,
			},
		});
	}

	public override async run(accessor: ServicesAccessor, editor: ICodeEditor): Promise<void> {
		const quickInputService = accessor.get(IQuickInputService);
		const model = editor.getModel();
		if (!model) {
			return;
		}

		const namedRegions = computeNamedRegions(model);
		if (namedRegions.length === 0) {
			return;
		}

		interface RegionPickItem extends IQuickPickItem {
			startLineNumber: number;
			endLineNumber: number;
		}

		const items: RegionPickItem[] = namedRegions.map(r => ({
			label: r.name || nls.localize('goToNamedRegion.unnamed', "(unnamed)"),
			description: nls.localize('goToNamedRegion.lineDesc', "Line {0}", r.startLineNumber),
			startLineNumber: r.startLineNumber,
			endLineNumber: r.endLineNumber,
		}));

		const disposables = new DisposableStore();
		const quickPick = disposables.add(quickInputService.createQuickPick<RegionPickItem>());
		quickPick.items = items;
		quickPick.placeholder = nls.localize('goToNamedRegion.placeholder', "Type to filter named regions");
		quickPick.matchOnDescription = true;

		disposables.add(quickPick.onDidAccept(() => {
			const selected = quickPick.selectedItems[0];
			if (selected) {
				_navigateToRegion(editor, selected.startLineNumber);
			}
			quickPick.hide();
		}));

		disposables.add(quickPick.onDidHide(() => disposables.dispose()));

		quickPick.show();
	}
}

/**
 * Navigates the editor cursor to `lineNumber`, unfolding any collapsed regions that
 * contain or start at that line.
 */
function _navigateToRegion(editor: ICodeEditor, lineNumber: number): void {
	const foldingController = FoldingController.get(editor);
	const foldingModelPromise = foldingController?.getFoldingModel();

	const doReveal = () => {
		editor.setSelection({
			startLineNumber: lineNumber,
			startColumn: 1,
			endLineNumber: lineNumber,
			endColumn: 1,
		});
		editor.revealPositionInCenterIfOutsideViewport({ lineNumber, column: 1 }, ScrollType.Smooth);
	};

	if (foldingModelPromise) {
		foldingModelPromise.then(foldingModel => {
			if (foldingModel) {
				// Unfold any collapsed region that starts exactly at the target line or
				// that contains the target line.
				const toUnfold: FoldingRegion[] = foldingModel.getAllRegionsAtLine(
					lineNumber,
					r => r.isCollapsed,
				);
				if (toUnfold.length > 0) {
					foldingModel.toggleCollapseState(toUnfold);
				}
			}
			doReveal();
		}).then(undefined, onUnexpectedError);
	} else {
		doReveal();
	}
}

/**
 * Provides `ModelDecorationOptions` for the inline region-name label that appears
 * after the `#region` marker when a named region is expanded.
 */
class NamedRegionDecorationProvider {
	private static readonly _decorationOptionsCache = new Map<string, ModelDecorationOptions>();

	static getDecorationOptions(regionName: string): ModelDecorationOptions {
		let options = NamedRegionDecorationProvider._decorationOptionsCache.get(regionName);
		if (!options) {
			options = ModelDecorationOptions.createDynamic({
				description: 'named-region-label',
				stickiness: TrackedRangeStickiness.NeverGrowsWhenTypingAtEdges,
				after: {
					content: ` \u00a0${regionName}\u00a0`,
					inlineClassName: 'named-region-label',
					inlineClassNameAffectsLetterSpacing: false,
				},
			});
			NamedRegionDecorationProvider._decorationOptionsCache.set(regionName, options);
		}
		return options;
	}
}


