/*---------------------------------------------------------------------------------------------
 *  Copyright (c) Microsoft Corporation. All rights reserved.
 *  Licensed under the MIT License. See License.txt in the project root for license information.
 *--------------------------------------------------------------------------------------------*/

import assert from 'assert';
import { ensureNoDisposablesAreLeakedInTestSuite } from '../../../../../base/test/common/utils.js';
import { createTextModel } from '../../../../test/common/testTextModel.js';
import { computeNamedRegions, NamedRegion } from '../../browser/namedFoldingRangeProvider.js';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function assertNamedRegions(lines: string[], expected: NamedRegion[]): void {
	const model = createTextModel(lines.join('\n'));
	const actual = computeNamedRegions(model);
	assert.deepStrictEqual(actual, expected);
	model.dispose();
}

function region(name: string, startLineNumber: number, endLineNumber: number): NamedRegion {
	return { name, startLineNumber, endLineNumber };
}

// ---------------------------------------------------------------------------
// Suite
// ---------------------------------------------------------------------------

suite('Named Folding Region Provider', () => {
	ensureNoDisposablesAreLeakedInTestSuite();

	// -- Basic detection ---------------------------------------------------------

	test('detects a single named region with // comment style', () => {
		assertNamedRegions([
			/* 1 */ '// #region MySection',
			/* 2 */ 'const x = 1;',
			/* 3 */ '// #endregion',
		], [region('MySection', 1, 3)]);
	});

	test('detects a single named region with # comment style', () => {
		assertNamedRegions([
			/* 1 */ '# #region DataProcessing',
			/* 2 */ 'print("hello")',
			/* 3 */ '# #endregion',
		], [region('DataProcessing', 1, 3)]);
	});

	test('detects a bare #region directive (no comment prefix)', () => {
		assertNamedRegions([
			/* 1 */ '#region Utilities',
			/* 2 */ 'void helper() {}',
			/* 3 */ '#endregion',
		], [region('Utilities', 1, 3)]);
	});

	test('detects a region with no name (empty name)', () => {
		assertNamedRegions([
			/* 1 */ '// #region',
			/* 2 */ 'const y = 2;',
			/* 3 */ '// #endregion',
		], [region('', 1, 3)]);
	});

	test('strips trailing whitespace from the region name', () => {
		assertNamedRegions([
			/* 1 */ '// #region   Trimmed   ',
			/* 2 */ 'code();',
			/* 3 */ '// #endregion',
		], [region('Trimmed', 1, 3)]);
	});

	// -- Multiple and nested regions ---------------------------------------------

	test('detects multiple sequential named regions', () => {
		assertNamedRegions([
			/* 1 */ '// #region Alpha',
			/* 2 */ 'const a = 1;',
			/* 3 */ '// #endregion',
			/* 4 */ '// #region Beta',
			/* 5 */ 'const b = 2;',
			/* 6 */ '// #endregion',
		], [
			region('Alpha', 1, 3),
			region('Beta', 4, 6),
		]);
	});

	test('detects nested named regions (inner resolved first, then outer)', () => {
		assertNamedRegions([
			/* 1 */ '// #region Outer',
			/* 2 */ '// #region Inner',
			/* 3 */ 'code();',
			/* 4 */ '// #endregion',
			/* 5 */ '// #endregion',
		], [
			// Sorted by startLineNumber: Outer (1) then Inner (2)
			region('Outer', 1, 5),
			region('Inner', 2, 4),
		]);
	});

	test('handles deeply nested regions', () => {
		assertNamedRegions([
			/* 1 */ '#region A',
			/* 2 */ '#region B',
			/* 3 */ '#region C',
			/* 4 */ 'code();',
			/* 5 */ '#endregion',
			/* 6 */ '#endregion',
			/* 7 */ '#endregion',
		], [
			region('A', 1, 7),
			region('B', 2, 6),
			region('C', 3, 5),
		]);
	});

	// -- Unmatched markers -------------------------------------------------------

	test('ignores #region without a matching #endregion', () => {
		assertNamedRegions([
			/* 1 */ '// #region NoEnd',
			/* 2 */ 'const z = 3;',
		], []);
	});

	test('ignores extra #endregion without a matching #region', () => {
		assertNamedRegions([
			/* 1 */ '// #endregion',
			/* 2 */ '// #region Matched',
			/* 3 */ 'code();',
			/* 4 */ '// #endregion',
		], [region('Matched', 2, 4)]);
	});

	// -- Mixed comment styles ----------------------------------------------------

	test('handles -- comment style (SQL / Lua)', () => {
		assertNamedRegions([
			/* 1 */ '-- #region Queries',
			/* 2 */ 'SELECT 1;',
			/* 3 */ '-- #endregion',
		], [region('Queries', 1, 3)]);
	});

	test('handles /* block comment style', () => {
		assertNamedRegions([
			/* 1 */ '/* #region BlockStyle */',
			/* 2 */ 'code();',
			/* 3 */ '/* #endregion */',
		], [region('BlockStyle', 1, 3)]);
	});

	// -- Name extraction ---------------------------------------------------------

	test('extracts multi-word region names', () => {
		assertNamedRegions([
			/* 1 */ '// #region My Complex Section Name',
			/* 2 */ 'code();',
			/* 3 */ '// #endregion',
		], [region('My Complex Section Name', 1, 3)]);
	});

	test('is case-insensitive for the #region keyword', () => {
		assertNamedRegions([
			/* 1 */ '// #Region CaseSensitivity',
			/* 2 */ 'code();',
			/* 3 */ '// #EndRegion',
		], [region('CaseSensitivity', 1, 3)]);
	});

	// -- Document with no regions ------------------------------------------------

	test('returns empty array when there are no region markers', () => {
		assertNamedRegions([
			'const x = 1;',
			'const y = 2;',
		], []);
	});

	test('returns empty array for an empty document', () => {
		assertNamedRegions([], []);
	});

	// -- Result ordering ---------------------------------------------------------

	test('results are sorted by startLineNumber', () => {
		// Two sequential regions — result must be in document order
		assertNamedRegions([
			/* 1 */ '#region First',
			/* 2 */ '#endregion',
			/* 3 */ '#region Second',
			/* 4 */ '#endregion',
		], [
			region('First', 1, 2),
			region('Second', 3, 4),
		]);
	});
});

