/**
 * Matches a `#endregion` marker with the same optional comment prefixes.
 */
const REGION_END_PATTERN = /^\s*(?:\/\/|#|--|\/\*|<!--|rem\b|')\s*#endregion\b|^\s*#endregion\b/i;

const ID_NAMED_REGION_PROVIDER = 'namedRegion';

