        /**
         * Apply inline "after-content" decorations that show the region name to the right of
         * the `#region` marker line.  This gives a visual hint even when the region is expanded.
         */
        private _updateNamedRegionDecorations(model: ITextModel): void {
                const namedRegions = computeNamedRegions(model);
                this.editor.changeDecorations(accessor => {
                        this._namedRegionDecorationIds = accessor.deltaDecorations(
                                this._namedRegionDecorationIds,
                                namedRegions
