                                                        startColumn: model.getLineMaxColumn(r.startLineNumber),
                                                        endLineNumber: r.startLineNumber,
                                                        endColumn: model.getLineMaxColumn(r.startLineNumber),
                                                },
                                                options: NamedRegionDecorationProvider.getDecorationOptions(r.name),
                                        })),
                        );
                });
