    58		const result: NamedRegion[] = [];
    59	
    60		for (let lineNumber = 1; lineNumber <= lineCount; lineNumber++) {
    61			const lineContent = model.getLineContent(lineNumber);
    62	
    63			const startMatch = lineContent.match(REGION_START_PATTERN);
    64			if (startMatch) {
    65				// Capture group 1 (comment-prefixed form) or group 2 (bare form)
    66				const name = (startMatch[1] ?? startMatch[2] ?? '').trim();
    67				stack.push({ name, startLineNumber: lineNumber });
    68				continue;
    69			}
    70	
    71			if (REGION_END_PATTERN.test(lineContent)) {
    72				const pending = stack.pop();
    73				if (pending) {
    74					result.push({
    75						name: pending.name,
    76						startLineNumber: pending.startLineNumber,
    77						endLineNumber: lineNumber,
    78					});
    79				}
    80			}
    81		}
    82	
    83		// Sort by start line so consumers can rely on document order
    84		result.sort((a, b) => a.startLineNumber - b.startLineNumber);
    85	
    86		return result;
    87	}
