    89	/**
    90	 * A `RangeProvider` that exposes `#region` / `#endregion` blocks as folding ranges.
    91	 * This provider works in addition to the language-specific providers and produces
    92	 * regions whose `type` is set to `'namedRegion'` so that they can be distinguished
    93	 * from other folding ranges.
    94	 */
    95	export class NamedFoldingRangeProvider implements RangeProvider {
    96		readonly id = ID_NAMED_REGION_PROVIDER;
    97	
    98		constructor(
    99			private readonly editorModel: ITextModel,
   100			private readonly foldingRangesLimit: FoldingLimitReporter,
   101		) { }
   102	
   103		dispose(): void { }
   104	
   105		compute(_cancellationToken: CancellationToken): Promise<FoldingRegions | null> {
   106			const namedRegions = computeNamedRegions(this.editorModel);
   107	
   108			const count = namedRegions.length;
   109			const limit = this.foldingRangesLimit.limit;
   110			const effectiveCount = Math.min(count, limit);
   111			this.foldingRangesLimit.update(count, count > limit ? limit : false);
   112	
   113			const startIndexes = new Uint32Array(effectiveCount);
   114			const endIndexes = new Uint32Array(effectiveCount);
   115			const types: Array<string | undefined> = new Array(effectiveCount);
   116	
   117			for (let i = 0; i < effectiveCount; i++) {
   118				startIndexes[i] = namedRegions[i].startLineNumber;
   119				endIndexes[i] = namedRegions[i].endLineNumber;
   120				types[i] = `namedRegion:${namedRegions[i].name}`;
   121			}
   122	
   123			return Promise.resolve(new FoldingRegions(startIndexes, endIndexes, types));
   124		}
   125	}
